module shift_register_8bit (
    input clk,
    input reset,
    input serial_in,
    output reg [7:0] q);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (reset)
        q <= 8'b00000000;
    else
        q <= {q[6:0], serial_in};
    end

endmodule
